package com.hsf.group1.controller;

import jakarta.servlet.http.HttpSession;
import java.util.ArrayList;
import java.util.List;
import com.hsf.group1.entities.Department;
import com.hsf.group1.entities.Lecturer;
import com.hsf.group1.service.DepartmentService;
import com.hsf.group1.service.LecturerService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;

/**
 *
 * @author Legion
 */
@Controller
public class LecturerController {

    private final LecturerService lecturerService;
    private final DepartmentService departmentService;

    @Autowired
    public LecturerController(LecturerService lecturerService, DepartmentService departmentService) {
        this.lecturerService = lecturerService;
        this.departmentService = departmentService;
    }

    /**
     * Processes requests for both HTTP <code>GET</code> and <code>POST</code>
     * methods.
     *
     * @param request servlet request
     * @param response servlet response
     * @throws ServletException if a servlet-specific error occurs
     * @throws IOException if an I/O error occurs
     */
    @GetMapping("/lecturer")
    public String doGet(
            @RequestParam(name = "action", required = false, defaultValue = "all") String action,
            @RequestParam(name = "i", required = false) String i,
            @RequestParam(name = "id", required = false) Integer id,
            @RequestParam(name = "nameLecturer", required = false) String lecturerName,
            @RequestParam(name = "departmentCode", required = false) String depCode,
            Model model) {
        int pagSize = 10;
        int pagIndex = 1;
        int totalPage = 0;

        if (i != null) {
            try {
                pagIndex = Integer.parseInt(i);
            } catch (NumberFormatException e) {
                pagIndex = 1;
            }
        }
        model.addAttribute("filter", false);

        switch (action) {
            case "all":
                List<Lecturer> list = lecturerService.getAllLecturers();
                totalPage = (list.size() + pagSize - 1) / pagSize;
                List<Lecturer> listPag = pagnigation(list, pagIndex, pagSize);

                model.addAttribute("listLecturer", listPag);
                model.addAttribute("page", pagIndex);
                model.addAttribute("totalPage", totalPage);
                model.addAttribute("listDepartments", departmentService.getAllDepartments());
                model.addAttribute("home_view", "lecturer.jsp");
                return "dashboard";
            case "delete":
                if (id == null) return "redirect:/lecturer?action=all";
                Lecturer lecturer = lecturerService.getLecturerById(id);
                model.addAttribute("lecturer", lecturer);
                model.addAttribute("home_view", "deleteLecturer.jsp");
                return "dashboard";
            case "edit":
                if (id == null) return "redirect:/lecturer?action=all";
                Lecturer ulecturer = lecturerService.getLecturerById(id);
                List<Department> departmentList = departmentService.getAllDepartments();

                model.addAttribute("departmentList", departmentList);
                model.addAttribute("lecturer", ulecturer);
                model.addAttribute("home_view", "editLecturer.jsp");
                return "dashboard";
            case "view":
                if (id == null) return "redirect:/lecturer?action=all";
                Lecturer vlecturer = lecturerService.getLecturerById(id);
                model.addAttribute("lecturer", vlecturer);
                model.addAttribute("home_view", "viewLecturer.jsp");
                return "dashboard";
            case "add":
                List<Department> depList = departmentService.getAllDepartments();
                model.addAttribute("departmentList", depList);
                model.addAttribute("home_view", "createLecturer.jsp");
                return "dashboard";
            case "fillter":
                model.addAttribute("filter", true);
                model.addAttribute("listDepartments", departmentService.getAllDepartments());

                if (lecturerName == null || lecturerName.trim().isEmpty()) {
                    lecturerName = "";
                }
                if (depCode == null || depCode.equalsIgnoreCase("all") || depCode.isEmpty()) {
                    depCode = "";
                }

                List<Lecturer> filteredList;

                if (!depCode.isEmpty() && !lecturerName.isEmpty()) {
                    filteredList = lecturerService.filterByBoth(depCode, lecturerName);
                } else if (!depCode.isEmpty()) {
                    filteredList = lecturerService.filterByDepartmentCode(depCode);
                } else if (!lecturerName.isEmpty()) {
                    filteredList = lecturerService.filterByName(lecturerName);
                } else {
                    filteredList = lecturerService.getAllLecturers();
                    request.setAttribute("filter", false);
                }

                totalPage = (filteredList.size() + pagSize - 1) / pagSize;
                List<Lecturer> listPagF = pagnigation(filteredList, pagIndex, pagSize);

                model.addAttribute("listLecturer", listPagF);
                model.addAttribute("page", pagIndex);
                model.addAttribute("totalPage", totalPage);
                model.addAttribute("nameLecturer", lecturerName);
                model.addAttribute("departmentCode", depCode);
                model.addAttribute("home_view", "lecturer.jsp");
                return "dashboard";
            default:
                return "redirect:/lecturer?action=all";
        }
    }

    /**
     * Handles the HTTP <code>POST</code> method.
     *
     * @param request servlet request
     * @param response servlet response
     * @throws ServletException if a servlet-specific error occurs
     * @throws IOException if an I/O error occurs
     */
    @PostMapping("/lecturer")
    public String doPost(
            @RequestParam(name = "action", required = false, defaultValue = "all") String action,
            @RequestParam(name = "lecturerId", required = false) Integer lecturerId,
            @RequestParam(name = "lecturerID", required = false) Integer lecturerID,
            @RequestParam(name = "lecturerName", required = false) String lecturerName,
            @RequestParam(name = "email", required = false) String email,
            @RequestParam(name = "depCode", required = false) String depCode,
            @RequestParam(name = "department", required = false) String department,
            @RequestParam(name = "title", required = false) String title,
            @RequestParam(name = "phone", required = false) String phone,
            HttpSession session) {

        switch (action) {
            case "delete":
                if (lecturerId == null) return "redirect:/lecturer?action=all";
                try {
                    boolean deleteSuccess = lecturerService.deleteLecturerById(lecturerId);
                    if (deleteSuccess) {
                        session.setAttribute("message", "Lecturer deleted successfully!");
                        session.setAttribute("messageType", "success");
                    } else {
                        session.setAttribute("message", "Failed to delete lecturer!");
                        session.setAttribute("messageType", "error");
                    }
                } catch (Exception e) {
                    if (e.getMessage().contains("FK_Classes_Lecturer")) {
                        session.setAttribute("message", "Cannot delete lecturer. They are still assigned to a class.");
                    } else {
                        session.setAttribute("message", "Failed to delete lecturer: " + e.getMessage());
                    }
                    session.setAttribute("messageType", "error");
                }
                return "redirect:/lecturer";

            case "edit":
                if (lecturerID == null) return "redirect:/lecturer?action=all";
                Department dep = departmentService.getDepartmentByCode(depCode);
                Lecturer eLecturer = new Lecturer(lecturerID, lecturerName, email, phone, title, dep);
                Boolean updateSuccess = lecturerService.updateLecturer(eLecturer);
                if (updateSuccess) {
                    session.setAttribute("message", "Lecturer update successfully!");
                    session.setAttribute("messageType", "success");
                } else {
                    session.setAttribute("message", "Failed to update lecturer!");
                    session.setAttribute("messageType", "error");
                }
                return "redirect:/lecturer";
            case "add":
                Department aDep = departmentService.getDepartmentByCode(department);
                Lecturer aLecturer = new Lecturer(lecturerName, email, phone, title, aDep);
                Boolean addSuccess = lecturerService.addNewLecturer(aLecturer);
                if (addSuccess) {
                    session.setAttribute("message", "Lecturer added successfully!");
                    session.setAttribute("messageType", "success");
                } else {
                    session.setAttribute("message", "Failed to add new lecturer!");
                    session.setAttribute("messageType", "error");
                }
                return "redirect:/lecturer";
            default:
                return "redirect:/lecturer?action=all";
        }
    }

    public List<Lecturer> pagnigation(List<Lecturer> list, int pageIndex, int pagsize) {
        if (list == null || list.isEmpty()) {
            return new ArrayList<>();
        }
        int StudentIndexBegin = (pageIndex - 1) * pagsize;

        if (StudentIndexBegin >= list.size()) {
            return new ArrayList<>();
        }

        int StudentIndexLast = (pageIndex * pagsize);

        if (StudentIndexLast > list.size()) {
            StudentIndexLast = list.size();
        }

        return list.subList(StudentIndexBegin, StudentIndexLast);
    }


}

